        /**
         * @description Campaign deferredBatchCount:
         *     Defines the number of batches the campaign will be split into.
         *     Used with `incremental` and `fixed_batches_by_count` strategies.
         *     The system will calculate the size of each batch automatically based on the total number of recipients.
         *     Example: 5 → campaign will be sent in 5 equal or progressively sized batches.
         * @enum {integer}
         */
        CampaignDeferredBatchCount: 2 | 3 | 4 | 5 | 6 | 8 | 10 | 12 | 15 | 20;
        /**
         * @description Campaign deferredBatchSize:
         *     Defines the number of recipients to send in each batch (used with fixed_batches_by_size strategy).
         * @enum {integer}
         */
        CampaignDeferredBatchSize: 250 | 500 | 1000 | 2000 | 5000 | 7500 | 10000 | 15000 | 20000 | 30000;
        /**
         * @description Campaign deferredInterval:
         *     Defines the interval between each batch (e.g., 30 minutes, 1 hour).
         * @enum {string}
         */
        CampaignDeferredInterval: "15 minutes" | "30 minutes" | "1 hour" | "2 hours" | "3 hours" | "6 hours" | "12 hours" | "24 hours";
        /**
         * @description Campaign deferredStrategy:
         *     * `incremental` - Sends the campaign in a predefined number of batches at regular intervals. Each batch increases in size automatically.
         *     * `fixed_batches_by_size` - Sends a fixed number of recipients in each batch (e.g., 5,000 recipients every 30 minutes).
         *     * `fixed_batches_by_count` - Sends the campaign in a predefined number of batches, automatically calculating the size of each batch (e.g., 5 batches every 30 minutes).
         * @enum {string}
         */
        CampaignDeferredStrategy: "incremental" | "fixed_batches_by_count" | "fixed_batches_by_size";
        /**
         * @description Campaign delivery warning codes:
         *     * `campaign.delivery_warning.no_active_subscribers` - No active subscribers (danger, blocks sending)
         *     * `campaign.delivery_warning.insufficient_credits` - Insufficient credits (danger, blocks sending)
         *     * `campaign.delivery_warning.daily_limit_exceeded` - Daily limit exceeded (warning, blocks sending)
         *     * `campaign.delivery_warning.send_disabled` - Sending disabled (danger, blocks sending)
         *     * `campaign.delivery_warning.approval_required` - Approval required (danger, blocks sending)
         *     * `campaign.delivery_warning.approval_pending` - Approval pending (danger, blocks sending)
         *     * `campaign.delivery_warning.cannot_send_without_authenticate` - Cannot send >1000 without auth (danger, blocks sending)
         *     * `campaign.delivery_warning.sender_domain_not_authenticated` - Domain not authenticated (warning)
         *     * `campaign.delivery_warning.custom_tracking_links_error` - Tracking links SSL/DNS error (warning)
         *     * `campaign.delivery_warning.free_email_provider` - Free email provider (warning)
         *     * `campaign.delivery_warning.domain_authentication_not_created` - Domain auth not created (warning)
         * @enum {string}
         */
        CampaignDeliveryWarningCode: "campaign.delivery_warning.no_active_subscribers" | "campaign.delivery_warning.insufficient_credits" | "campaign.delivery_warning.daily_limit_exceeded" | "campaign.delivery_warning.send_disabled" | "campaign.delivery_warning.approval_required" | "campaign.delivery_warning.approval_pending" | "campaign.delivery_warning.cannot_send_without_authenticate" | "campaign.delivery_warning.sender_domain_not_authenticated" | "campaign.delivery_warning.custom_tracking_links_error" | "campaign.delivery_warning.free_email_provider" | "campaign.delivery_warning.domain_authentication_not_created";
